#nullable enable // autogenerated  

using System.Collections.Generic;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.amethystPylon_Lit)]
    public class AmethystPylon_Lit : EntityBehaviourDefinition
    {
        public AmethystPylon_Lit(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new FloatModifier(VanillaEntityProps.DAMAGE, NumberOperator.Multiply, PROP_DAMAGE_MULTIPLIER));
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            var timer = GetCheckTimer(entity);
            if (timer == null)
            {
                timer = TimerHelper.NewSecondTimer(CHECK_SECONDS);
                SetCheckTimer(entity, timer);
            }
            if (timer.RunToExpired())
            {
                lightSourceBuffer.Clear();
                entity.Level.GetIlluminationLightSourcesNonAlloc(entity, lightSourceBuffer);
                int count = 0;      // 有效光源数量(用于伤害倍率，保留原逻辑)  
                int levelSum = 0;   // 入射光等级之和(用于八色光谱输出)  
                if (entity.Level.IsDay())
                {
                    count++;
                    // 白天视为等级 0 的白光：计入"有光"，对 levelSum 贡献 0  
                }
                foreach (var source in lightSourceBuffer)
                {
                    var sourceEntity = entity.Level.FindEntityByID(source);
                    if (sourceEntity.ExistsAndAlive() && (sourceEntity.IsVulnerableEntity() || sourceEntity.Type == EntityTypes.CART))
                    {
                        count++;
                        // 只累加声明了等级(>=0)的光源；旧光源默认 -1 不参与  
                        var level = sourceEntity.GetLightLevel();
                        if (level >= 0)
                        {
                            levelSum += level;
                        }
                    }
                }
                // 注意：这里不再像原来那样在 count>=MAX 时 break，  
                // 以保证 levelSum 能统计到所有入射光；count 仍按上限 clamp。  
                count = Mathf.Clamp(count, 0, MAX_LIGHT_SOURCE_COUNT);
                SetDamageMultiplier(entity, Mathf.Max(count * 2, 1));
                SetIncidentSum(entity, levelSum);
                entity.SetModelProperty("LightSourceCount", count);
                entity.SetModelProperty("IncidentSum", levelSum);
                timer.Reset();
            }
        }
        public static FrameTimer? GetCheckTimer(Entity entity) => entity.GetBehaviourField<FrameTimer>(PROP_CHECK_TIMER);
        public static void SetCheckTimer(Entity entity, FrameTimer? timer) => entity.SetBehaviourField(PROP_CHECK_TIMER, timer);
        public static float GetDamageMultiplier(Entity entity) => entity.GetBehaviourField<float>(PROP_DAMAGE_MULTIPLIER);
        public static void SetDamageMultiplier(Entity entity, float value) => entity.SetBehaviourField(PROP_DAMAGE_MULTIPLIER, value);
        // 累计入射光等级之和，供 AmethystPylon.Attack 做快照  
        public static int GetIncidentSum(Entity entity) => entity.GetBehaviourField<int>(PROP_INCIDENT_SUM);
        public static void SetIncidentSum(Entity entity, int value) => entity.SetBehaviourField(PROP_INCIDENT_SUM, value);

        public const int MAX_LIGHT_SOURCE_COUNT = 3;
        public const float CHECK_SECONDS = 7 / 30f;
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_CHECK_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("check_timer");
        public static readonly VanillaEntityPropertyMeta<float> PROP_DAMAGE_MULTIPLIER = new VanillaEntityPropertyMeta<float>("damage_multiplier");
        public static readonly VanillaEntityPropertyMeta<int> PROP_INCIDENT_SUM = new VanillaEntityPropertyMeta<int>("incident_sum");
        private static HashSet<long> lightSourceBuffer = new HashSet<long>();
    }
}
